class City {
  String id;
  String name;

  City({
    required this.id,
    required this.name,
  });

  factory City.fromJson(Map<String, dynamic> json) {
    return City(
      id: json['id'] ?? '',
      name: json['name'] ?? '',
    );
  }

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'name': name,
    };
  }
}

class Masjid {
  String id;
  String name;
  String societyId;
  String imamId;
  String fajr;
  String zuhr;
  String asr;
  String maghrib;
  String isha;
  String jummah;
  String status;

  Masjid({
    required this.id,
    required this.name,
    required this.societyId,
    required this.imamId,
    required this.fajr,
    required this.zuhr,
    required this.asr,
    required this.maghrib,
    required this.isha,
    required this.jummah,
    this.status = 'pending',
  });

  factory Masjid.fromJson(Map<String, dynamic> json) {
    return Masjid(
      id: json['id'] ?? '',
      name: json['name'] ?? '',
      societyId: json['society_id'] ?? '',
      imamId: json['imam_id'] ?? '',
      fajr: json['fajr'] ?? '',
      zuhr: json['zuhr'] ?? '',
      asr: json['asr'] ?? '',
      maghrib: json['maghrib'] ?? '',
      isha: json['isha'] ?? '',
      jummah: json['jummah'] ?? '',
      status: json['status'] ?? 'pending',
    );
  }

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'name': name,
      'society_id': societyId,
      'imam_id': imamId,
      'fajr': fajr,
      'zuhr': zuhr,
      'asr': asr,
      'maghrib': maghrib,
      'isha': isha,
      'jummah': jummah,
      'status': status,
    };
  }
}

class Restaurant {
  String id;
  String name;
  String societyId;
  String ownerId;
  String phone;
  String category;
  bool deliveryAvailable;
  String status;

  Restaurant({
    required this.id,
    required this.name,
    required this.societyId,
    required this.ownerId,
    required this.phone,
    required this.category,
    this.deliveryAvailable = false,
    this.status = 'pending',
  });

  factory Restaurant.fromJson(Map<String, dynamic> json) {
    return Restaurant(
      id: json['id'] ?? '',
      name: json['name'] ?? '',
      societyId: json['society_id'] ?? '',
      ownerId: json['owner_id'] ?? '',
      phone: json['phone'] ?? '',
      category: json['category'] ?? '',
      deliveryAvailable: json['delivery_available'] ?? false,
      status: json['status'] ?? 'pending',
    );
  }

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'name': name,
      'society_id': societyId,
      'owner_id': ownerId,
      'phone': phone,
      'category': category,
      'delivery_available': deliveryAvailable,
      'status': status,
    };
  }
}

