import 'package:flutter/material.dart';
import 'home_screen.dart';

class SocietyScreen extends StatefulWidget {
  final String cityName;

  SocietyScreen({required this.cityName});

  @override
  _SocietyScreenState createState() => _SocietyScreenState();
}

class _SocietyScreenState extends State<SocietyScreen> {
  // Mock data - will be replaced with Firebase data
  late Map<String, List<String>> citySocieties;

  final TextEditingController searchController = TextEditingController();
  String searchQuery = '';
  List<String> filteredSocieties = [];

  @override
  void initState() {
    super.initState();
    citySocieties = {
      "Karachi": [
        "DHA Phase 6",
        "Bahria Town Karachi",
        "Gulshan-e-Iqbal",
        "North Nazimabad",
        "Clifton",
      ],
      "Lahore": [
        "DHA Lahore",
        "Bahria Town Lahore",
        "Gulberg",
        "Canal Road",
        "Model Town",
      ],
      "Islamabad": [
        "F-7 Sector",
        "G-6 Sector",
        "Bahria Town Islamabad",
        "Defense",
        "Banigala",
      ],
      "Rawalpindi": [
        "Adiala Road",
        "Bahria Town Rawalpindi",
        "Attock Road",
        "Saddar",
        "Wapda Town",
      ],
      "Hyderabad": [
        "Latifabad",
        "Qasimabad",
        "Colonial Road",
        "Hirabad",
      ],
      "Faisalabad": [
        "Civil Lines",
        "Iqbal Town",
        "Peoples Colony",
        "Ghulberg",
      ],
      "Multan": [
        "Cantonment",
        "Zargarabad",
        "Mumtazabad",
      ],
      "Peshawar": [
        "Cantonment",
        "University Town",
        "Hayatabad",
      ],
      "Quetta": [
        "Cantonment",
        "New Quetta",
        "Brewary Road",
      ],
      "Sialkot": [
        "Cantonment",
        "City",
        "Begumabad",
      ],
    };

    filteredSocieties = citySocieties[widget.cityName] ?? [];
  }

  void _filterSocieties(String query) {
    setState(() {
      searchQuery = query;
      if (query.isEmpty) {
        filteredSocieties = citySocieties[widget.cityName] ?? [];
      } else {
        filteredSocieties = (citySocieties[widget.cityName] ?? [])
            .where((society) =>
                society.toLowerCase().contains(query.toLowerCase()))
            .toList();
      }
    });
  }

  void _showAddSocietyDialog() {
    final TextEditingController societyNameController =
        TextEditingController();

    showDialog(
      context: context,
      builder: (context) {
        return AlertDialog(
          title: Text("Add New Society"),
          content: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              Text(
                "City: ${widget.cityName}",
                style: TextStyle(fontWeight: FontWeight.bold),
              ),
              SizedBox(height: 15),
              TextField(
                controller: societyNameController,
                decoration: InputDecoration(
                  labelText: "Society Name",
                  hintText: "Enter society name",
                  border: OutlineInputBorder(),
                ),
              ),
            ],
          ),
          actions: [
            TextButton(
              onPressed: () => Navigator.pop(context),
              child: Text("Cancel"),
            ),
            ElevatedButton(
              onPressed: () {
                String societyName =
                    societyNameController.text.trim().toUpperCase();

                if (societyName.isEmpty) {
                  ScaffoldMessenger.of(context).showSnackBar(
                    SnackBar(content: Text("Please enter society name")),
                  );
                  return;
                }

                // Check for duplicates (exact match)
                bool isDuplicate = (citySocieties[widget.cityName] ?? [])
                    .any((s) => s.toUpperCase() == societyName);

                if (isDuplicate) {
                  ScaffoldMessenger.of(context).showSnackBar(
                    SnackBar(
                      content: Text(
                          "This society already exists. Please select it from the list."),
                      backgroundColor: Colors.orange,
                    ),
                  );
                  return;
                }

                // Add society
                setState(() {
                  citySocieties[widget.cityName]!
                      .add(societyNameController.text.trim());
                  filteredSocieties = citySocieties[widget.cityName] ?? [];
                  searchController.clear();
                  _filterSocieties('');
                });

                ScaffoldMessenger.of(context).showSnackBar(
                  SnackBar(
                    content: Text("Society added successfully!"),
                    backgroundColor: Colors.green,
                  ),
                );

                Navigator.pop(context);
              },
              child: Text("Add"),
            ),
          ],
        );
      },
    );
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text("${widget.cityName} - Societies"),
        centerTitle: true,
        elevation: 0,
      ),
      body: Column(
        children: [
          // Search Bar
          Padding(
            padding: EdgeInsets.all(16),
            child: TextField(
              controller: searchController,
              onChanged: _filterSocieties,
              decoration: InputDecoration(
                hintText: "Search societies...",
                prefixIcon: Icon(Icons.search),
                border: OutlineInputBorder(
                  borderRadius: BorderRadius.circular(10),
                ),
              ),
            ),
          ),
          // Societies List
          Expanded(
            child: filteredSocieties.isEmpty
                ? Center(
                    child: Column(
                      mainAxisAlignment: MainAxisAlignment.center,
                      children: [
                        Icon(Icons.location_off, size: 60, color: Colors.grey),
                        SizedBox(height: 10),
                        Text(
                          searchQuery.isEmpty
                              ? "No societies available"
                              : "No matching societies",
                          style: TextStyle(color: Colors.grey, fontSize: 16),
                        ),
                      ],
                    ),
                  )
                : ListView.builder(
                    itemCount: filteredSocieties.length,
                    itemBuilder: (context, index) {
                      String society = filteredSocieties[index];
                      return Card(
                        margin:
                            EdgeInsets.symmetric(horizontal: 10, vertical: 8),
                        elevation: 2,
                        child: ListTile(
                          leading: Icon(Icons.apartment),
                          title: Text(society),
                          trailing: Icon(Icons.arrow_forward),
                          onTap: () {
                            Navigator.push(
                              context,
                              MaterialPageRoute(
                                builder: (context) => HomeScreen(
                                  societyName: society,
                                  cityName: widget.cityName,
                                ),
                              ),
                            );
                          },
                        ),
                      );
                    },
                  ),
          ),
        ],
      ),
      floatingActionButton: FloatingActionButton(
        onPressed: _showAddSocietyDialog,
        tooltip: "Add New Society",
        child: Icon(Icons.add),
      ),
    );
  }

  @override
  void dispose() {
    searchController.dispose();
    super.dispose();
  }
}

import 'package:flutter/material.dart';
import '../screens/city_screen.dart';

class SplashScreen extends StatefulWidget {
  @override
  _SplashScreenState createState() => _SplashScreenState();
}

class _SplashScreenState extends State<SplashScreen> {
  @override
  void initState() {
    super.initState();

    Future.delayed(Duration(seconds: 3), () {
      if (mounted) {
        Navigator.pushReplacement(
          context,
          MaterialPageRoute(builder: (context) => CityScreen()),
        );
      }
    });
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      body: Container(
        decoration: BoxDecoration(
          gradient: LinearGradient(
            colors: [Colors.green[700]!, Colors.green[300]!],
            begin: Alignment.topLeft,
            end: Alignment.bottomRight,
          ),
        ),
        child: Center(
          child: Column(
            mainAxisAlignment: MainAxisAlignment.center,
            children: [
              Icon(Icons.location_city, size: 80, color: Colors.white),
              SizedBox(height: 20),
              Text(
                "SocioHub",
                style: TextStyle(
                  fontSize: 40,
                  fontWeight: FontWeight.bold,
                  color: Colors.white,
                ),
              ),
              SizedBox(height: 10),
              Text(
                "Community First",
                style: TextStyle(
                  fontSize: 16,
                  color: Colors.white70,
                ),
              ),
            ],
          ),
        ),
      ),
    );
  }
}

import 'package:flutter/material.dart';

class MenuCard extends StatelessWidget {
  final String title;
  final IconData icon;
  final VoidCallback onTap;

  const MenuCard({
    required this.title,
    required this.icon,
    required this.onTap,
  });

  @override
  Widget build(BuildContext context) {
    return GestureDetector(
      onTap: onTap,
      child: Card(
        elevation: 3,
        shape: RoundedRectangleBorder(
          borderRadius: BorderRadius.circular(10),
        ),
        child: Container(
          decoration: BoxDecoration(
            borderRadius: BorderRadius.circular(10),
            gradient: LinearGradient(
              colors: [Colors.green[300]!, Colors.green[700]!],
              begin: Alignment.topLeft,
              end: Alignment.bottomRight,
            ),
          ),
          child: Center(
            child: Column(
              mainAxisAlignment: MainAxisAlignment.center,
              children: [
                Icon(icon, size: 40, color: Colors.white),
                SizedBox(height: 10),
                Text(
                  title,
                  textAlign: TextAlign.center,
                  style: TextStyle(
                    fontSize: 14,
                    fontWeight: FontWeight.bold,
                    color: Colors.white,
                  ),
                )
              ],
            ),
          ),
        ),
      ),
    );
  }
}
